{"cli":"mcd extract --markdown {MCD_PATH}"}
{"sql":"select table_id, column_name, ordinal, ref_table_id, ref_column_name from mcd_foreign_keys order by table_id, ordinal"}
{"sql":"with eligible_variants as (select variant_id, tow_rating_kg, body_style, trim_level from vehicle_variant_configuration_specs where cast(tow_rating_kg as real) > 2000), passing_brakes as (select test_id, vehicle_variant, stop_distance_100_0_m from chassis_brake_validation_specs where cast(stop_distance_100_0_m as real) < 40) select pb.test_id, ev.variant_id, ev.tow_rating_kg, pb.stop_distance_100_0_m, ev.body_style, ev.trim_level from passing_brakes pb join eligible_variants ev on pb.vehicle_variant = ev.variant_id order by cast(pb.stop_distance_100_0_m as real) asc, pb.test_id asc limit 1"}
